   107→function renderRuleRow(planId, rule) {
   108→    return `
   109→        <tr>
   110→            <td class="text-mono">${rule.cpt_code}</td>
   111→            <td>${rule.is_covered ? "✓ Yes" : "✗ No"}</td>
   112→            <td>${(parseFloat(rule.coverage_percentage) * 100).toFixed(0)}%</td>
   113→            <td>
   114→                <button class="btn btn-outline btn-sm delete-rule-btn"
   115→                    data-plan="${planId}" data-cpt="${rule.cpt_code}">Delete</button>
   116→            </td>
   117→        </tr>`;
   118→}
