   120→function wirePlanCard(plan) {
   121→    // Upsert rule
   122→    const card = document.getElementById(`plan-card-${plan.id}`);
   123→    if (!card) return;
   124→
   125→    card.querySelectorAll(".upsert-rule-btn").forEach(btn => {
   126→        btn.addEventListener("click", async () => {
   127→            const pid     = btn.dataset.plan;
   128→            const cpt     = document.getElementById(`rule-cpt-${pid}`).value.trim();
   129→            const covered = document.getElementById(`rule-covered-${pid}`).value === "true";
   130→            const pct     = document.getElementById(`rule-pct-${pid}`).value;
   131→            const errEl   = document.getElementById(`rule-error-${pid}`);
   132→
   133→            if (!cpt || !pct) { showError(errEl, "CPT code and coverage % are required."); return; }
   134→
   135→            btn.disabled = true;
   136→            try {
   137→                await api.upsertCoverageRule(pid, cpt, { is_covered: covered, coverage_percentage: parseFloat(pct) });
   138→                await loadPlans();
   139→            } catch (err) {
   140→                showError(errEl, err.message);
   141→                btn.disabled = false;
   142→            }
   143→        });
   144→    });
   145→
   146→    // Delete rule
   147→    card.querySelectorAll(".delete-rule-btn").forEach(btn => {
   148→        btn.addEventListener("click", async () => {
   149→            if (!confirm(`Delete coverage rule for CPT ${btn.dataset.cpt}?`)) return;
   150→            btn.disabled = true;
   151→            try {
   152→                await api.deleteCoverageRule(btn.dataset.plan, btn.dataset.cpt);
   153→                await loadPlans();
   154→            } catch (err) {
   155→                alert(err.message);
   156→                btn.disabled = false;
   157→            }
   158→        });
   159→    });
   160→}
